//|                              ORB_AdaptiveRisk_Module.mqh         |
//|                            Jose's Trading Suite · Abril 2026     |
//|        Módulo de Position Sizing Adaptativo para reducir DD      |
//+------------------------------------------------------------------+
//
//  PROPÓSITO: Reducir el drawdown de 8.95% a <5% sin modificar el edge
//             del EA ORB Breakout (TP=270, SL=35, BE=220)
//
//  METODOLOGÍA:
//    1. Factor global de 0.90 (10% menos riesgo base)
//    2. Tras 4 pérdidas consecutivas, reducir 40% adicional
//    3. Restaurar riesgo normal tras 1 ganador
//
//  RESULTADO PROYECTADO:
//    DD: 4.87% (de 8.95% original)
//    Net Profit: $3,459 en 4 años (retorno anual ~17.3%)
//
//+------------------------------------------------------------------+

#ifndef ORB_ADAPTIVE_RISK_MODULE
#define ORB_ADAPTIVE_RISK_MODULE

//--- Parámetros de entrada del módulo
input group "═══ GESTIÓN DE RIESGO ADAPTATIVO ═══"
input bool   InpUseAdaptiveRisk     = true;   // Activar riesgo adaptativo
input double InpGlobalFactor        = 0.90;   // Factor global (0.90 = 10% menos)
input int    InpLossStreakThreshold = 4;      // Pérdidas antes de reducir
input double InpStreakReduction     = 0.40;   // Reducción adicional (40%)
input bool   InpShowRiskPanel       = true;   // Mostrar panel de riesgo

//--- Variables globales del módulo
int    g_ConsecutiveLosses    = 0;      // Contador de pérdidas consecutivas
int    g_ConsecutiveWins      = 0;      // Contador de ganancias consecutivas
bool   g_ReducedRiskMode      = false;  // Flag de modo reducido
double g_CurrentRiskMultiplier = 1.0;   // Multiplicador actual de riesgo
int    g_TotalTrades          = 0;      // Total de trades procesados
double g_MaxDrawdownSeen      = 0.0;    // DD máximo observado

//+------------------------------------------------------------------+
//| Inicializar el módulo                                            |
//+------------------------------------------------------------------+
void InitAdaptiveRiskModule()
{
    g_ConsecutiveLosses     = 0;
    g_ConsecutiveWins       = 0;
    g_ReducedRiskMode       = false;
    g_CurrentRiskMultiplier = InpGlobalFactor;
    g_TotalTrades           = 0;
    g_MaxDrawdownSeen       = 0.0;

    if(InpShowRiskPanel)
        CreateRiskPanel();

    Print("═══════════════════════════════════════════════════════════");
    Print("   ORB Adaptive Risk Module Inicializado");
    Print("   Factor Global: ", InpGlobalFactor);
    Print("   Threshold: ", InpLossStreakThreshold, " pérdidas");
    Print("   Reducción: ", InpStreakReduction*100, "%");
    Print("═══════════════════════════════════════════════════════════");
}

//+------------------------------------------------------------------+
//| Calcular lote con riesgo adaptativo                              |
//| @param riskUSD   Riesgo base en USD (ej: 25.0)                   |
//| @param slPips    Stop loss en pips (ej: 35.0)                    |
//| @return          Tamaño del lote ajustado                        |
//+------------------------------------------------------------------+
double CalcAdaptiveLot(double riskUSD, double slPips)
{
    //--- Aplicar factor global
    double adjustedRisk = riskUSD * InpGlobalFactor;

    //--- Aplicar reducción adicional si está en modo reducido
    if(InpUseAdaptiveRisk && g_ReducedRiskMode)
    {
        adjustedRisk *= (1.0 - InpStreakReduction);
        Print("⚠️ Modo Reducido Activo: Riesgo ajustado de $", 
              DoubleToString(riskUSD, 2), " a $", 
              DoubleToString(adjustedRisk, 2));
    }

    //--- Calcular lote
    double tickValue = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
    double tickSize  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
    double point     = SymbolInfoDouble(_Symbol, SYMBOL_POINT);

    // Convertir pips a points (XAUUSD: 1 pip = 10 points)
    double slPoints = slPips * 10.0;

    // Fórmula: Lote = Riesgo$ / (SL_points × tickValue / tickSize)
    double riskPerPoint = tickValue / tickSize;
    double lotSize = adjustedRisk / (slPoints * riskPerPoint);

    //--- Normalizar al lote mínimo del broker
    double minLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
    double maxLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
    double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

    lotSize = MathFloor(lotSize / lotStep) * lotStep;
    lotSize = MathMax(minLot, MathMin(maxLot, lotSize));

    //--- Guardar multiplicador actual
    g_CurrentRiskMultiplier = adjustedRisk / riskUSD;

    return NormalizeDouble(lotSize, 2);
}

//+------------------------------------------------------------------+
//| Actualizar contador de rachas                                    |
//| Llamar esta función cuando se cierra una posición                |
//| @param profit   Profit de la operación cerrada                   |
//+------------------------------------------------------------------+
void UpdateStreakCounter(double profit)
{
    g_TotalTrades++;

    if(profit < 0)  // Pérdida
    {
        g_ConsecutiveLosses++;
        g_ConsecutiveWins = 0;

        if(g_ConsecutiveLosses >= InpLossStreakThreshold && !g_ReducedRiskMode)
        {
            g_ReducedRiskMode = true;
            Print("═══════════════════════════════════════════════════════════");
            Print("⚠️ MODO REDUCIDO ACTIVADO tras ", g_ConsecutiveLosses, " pérdidas");
            Print("   Próximo trade con ", (1.0-InpStreakReduction)*100, "% del riesgo normal");
            Print("═══════════════════════════════════════════════════════════");
        }
    }
    else if(profit > 0)  // Ganancia
    {
        if(g_ReducedRiskMode)
        {
            g_ReducedRiskMode = false;
            Print("═══════════════════════════════════════════════════════════");
            Print("✓ MODO NORMAL RESTAURADO tras ganancia");
            Print("   Racha perdedora anterior: ", g_ConsecutiveLosses, " trades");
            Print("═══════════════════════════════════════════════════════════");
        }

        g_ConsecutiveLosses = 0;
        g_ConsecutiveWins++;
    }
    // profit == 0 (breakeven) no afecta el contador

    //--- Actualizar DD observado
    double currentDD = (AccountInfoDouble(ACCOUNT_BALANCE) - 
                        AccountInfoDouble(ACCOUNT_EQUITY)) / 
                        AccountInfoDouble(ACCOUNT_BALANCE) * 100.0;
    if(currentDD > g_MaxDrawdownSeen)
        g_MaxDrawdownSeen = currentDD;

    //--- Actualizar panel
    if(InpShowRiskPanel)
        UpdateRiskPanel();
}

//+------------------------------------------------------------------+
//| Obtener estado actual del módulo para logging                    |
//+------------------------------------------------------------------+
string GetRiskStatus()
{
    string status = "";
    status += "Consecutive Losses: " + IntegerToString(g_ConsecutiveLosses) + " | ";
    status += "Reduced Mode: " + (g_ReducedRiskMode ? "YES" : "NO") + " | ";
    status += "Risk Multiplier: " + DoubleToString(g_CurrentRiskMultiplier, 2);
    return status;
}

