    double currentDD = (AccountInfoDouble(ACCOUNT_BALANCE) - 
                        AccountInfoDouble(ACCOUNT_EQUITY)) / 
                        AccountInfoDouble(ACCOUNT_BALANCE) * 100.0;

    if(currentDD > 4.5)  // 4.5% = zona de peligro
    {
        Print("⛔ CIRCUITO BREAKER: DD actual ", DoubleToString(currentDD, 2), 
              "% excede zona segura. Trade bloqueado.");
        return false;
    }

    // Límite de rachas (emergencia extrema)
