    {
        Print("⛔ CIRCUITO BREAKER: ", g_ConsecutiveLosses, 
              " pérdidas consecutivas. Requiere revisión manual.");
        return false;
    }

    return true;
}

//+------------------------------------------------------------------+
//| Crear panel visual de riesgo                                     |
//+------------------------------------------------------------------+
void CreateRiskPanel()
{
    string prefix = "RISK_";
    int x = 10, y = 100;
    int width = 200, height = 100;

    // Fondo del panel
    ObjectCreate(0, prefix+"BG", OBJ_RECTANGLE_LABEL, 0, 0, 0);
    ObjectSetInteger(0, prefix+"BG", OBJPROP_XDISTANCE, x);
    ObjectSetInteger(0, prefix+"BG", OBJPROP_YDISTANCE, y);
    ObjectSetInteger(0, prefix+"BG", OBJPROP_XSIZE, width);
    ObjectSetInteger(0, prefix+"BG", OBJPROP_YSIZE, height);
    ObjectSetInteger(0, prefix+"BG", OBJPROP_BGCOLOR, C'20,20,30');
    ObjectSetInteger(0, prefix+"BG", OBJPROP_BORDER_TYPE, BORDER_FLAT);
    ObjectSetInteger(0, prefix+"BG", OBJPROP_CORNER, CORNER_LEFT_UPPER);
    ObjectSetInteger(0, prefix+"BG", OBJPROP_COLOR, C'60,60,80');
    ObjectSetInteger(0, prefix+"BG", OBJPROP_STYLE, STYLE_SOLID);
    ObjectSetInteger(0, prefix+"BG", OBJPROP_WIDTH, 1);

    // Título
    ObjectCreate(0, prefix+"Title", OBJ_LABEL, 0, 0, 0);
    ObjectSetInteger(0, prefix+"Title", OBJPROP_XDISTANCE, x+10);
    ObjectSetInteger(0, prefix+"Title", OBJPROP_YDISTANCE, y+10);
    ObjectSetInteger(0, prefix+"Title", OBJPROP_COLOR, clrGold);
    ObjectSetString(0, prefix+"Title", OBJPROP_TEXT, "▸ ADAPTIVE RISK");
    ObjectSetString(0, prefix+"Title", OBJPROP_FONT, "Arial Bold");
    ObjectSetInteger(0, prefix+"Title", OBJPROP_FONTSIZE, 9);

    // Labels
    string labels[] = {"Mode", "Streak", "Factor"};
    for(int i=0; i<3; i++)
    {
        ObjectCreate(0, prefix+"L"+IntegerToString(i), OBJ_LABEL, 0, 0, 0);
        ObjectSetInteger(0, prefix+"L"+IntegerToString(i), OBJPROP_XDISTANCE, x+10);
        ObjectSetInteger(0, prefix+"L"+IntegerToString(i), OBJPROP_YDISTANCE, y+30+i*20);
        ObjectSetInteger(0, prefix+"L"+IntegerToString(i), OBJPROP_COLOR, C'150,150,170');
        ObjectSetString(0, prefix+"L"+IntegerToString(i), OBJPROP_TEXT, labels[i]+" :");
        ObjectSetString(0, prefix+"L"+IntegerToString(i), OBJPROP_FONT, "Consolas");
        ObjectSetInteger(0, prefix+"L"+IntegerToString(i), OBJPROP_FONTSIZE, 8);

        // Valores
        ObjectCreate(0, prefix+"V"+IntegerToString(i), OBJ_LABEL, 0, 0, 0);
        ObjectSetInteger(0, prefix+"V"+IntegerToString(i), OBJPROP_XDISTANCE, x+70);
        ObjectSetInteger(0, prefix+"V"+IntegerToString(i), OBJPROP_YDISTANCE, y+30+i*20);
        ObjectSetString(0, prefix+"V"+IntegerToString(i), OBJPROP_FONT, "Consolas");
        ObjectSetInteger(0, prefix+"V"+IntegerToString(i), OBJPROP_FONTSIZE, 8);
    }

    UpdateRiskPanel();
}

//+------------------------------------------------------------------+
//| Actualizar panel visual de riesgo                                |
//+------------------------------------------------------------------+
void UpdateRiskPanel()
{
    string prefix = "RISK_";

    // Mode
    if(g_ReducedRiskMode)
    {
        ObjectSetInteger(0, prefix+"V0", OBJPROP_COLOR, clrOrange);
        ObjectSetString(0, prefix+"V0", OBJPROP_TEXT, "⚠️ REDUCED");
    }
    else
    {
        ObjectSetInteger(0, prefix+"V0", OBJPROP_COLOR, clrLime);
        ObjectSetString(0, prefix+"V0", OBJPROP_TEXT, "✓ NORMAL");
    }

    // Streak
    color streakColor = g_ConsecutiveLosses >= InpLossStreakThreshold ? clrRed : 
                        g_ConsecutiveLosses >= 2 ? clrOrange : clrWhite;
    ObjectSetInteger(0, prefix+"V1", OBJPROP_COLOR, streakColor);
    ObjectSetString(0, prefix+"V1", OBJPROP_TEXT, IntegerToString(g_ConsecutiveLosses)+" losses");

    // Factor
    ObjectSetInteger(0, prefix+"V2", OBJPROP_COLOR, clrWhite);
    ObjectSetString(0, prefix+"V2", OBJPROP_TEXT, DoubleToString(g_CurrentRiskMultiplier*100, 0)+"%");

    ChartRedraw();
}

//+------------------------------------------------------------------+
//| Destruir panel visual                                            |
//+------------------------------------------------------------------+
void DestroyRiskPanel()
{
    string prefix = "RISK_";
    ObjectsDeleteAll(0, prefix);
}

//+------------------------------------------------------------------+
//| Deinicializar el módulo                                          |
//+------------------------------------------------------------------+
void DeinitAdaptiveRiskModule()
{
    if(InpShowRiskPanel)
        DestroyRiskPanel();

    Print("═══════════════════════════════════════════════════════════");
    Print("   ORB Adaptive Risk Module - Resumen Final");
    Print("   Total Trades Procesados: ", g_TotalTrades);
    Print("   Max DD Observado: ", DoubleToString(g_MaxDrawdownSeen, 2), "%");
    Print("   Rachas Perdedoras Máximas: ", g_ConsecutiveLosses);
    Print("═══════════════════════════════════════════════════════════");
}

#endif // ORB_ADAPTIVE_RISK_MODULE
//+------------------------------------------------------------------+

